import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "esbuild";

const root = path.resolve(fileURLToPath(new URL("..", import.meta.url)));
const entryPoint = path.join(root, "src", "overlay", "browser-entry.ts");
const outputPath = path.join(
  root,
  "src",
  "core",
  "generated",
  "overlay-bundle.ts",
);

const result = await build({
  entryPoints: [entryPoint],
  bundle: true,
  format: "iife",
  platform: "browser",
  target: "es2020",
  minify: true,
  legalComments: "none",
  write: false,
  sourcemap: false,
  logLevel: "silent",
});

const bundled = result.outputFiles?.[0]?.text;

if (!bundled) {
  throw new Error("Failed to generate Vernier overlay bundle.");
}

await mkdir(path.dirname(outputPath), { recursive: true });
await writeFile(
  outputPath,
  [
    "// This file is generated by scripts/build-overlay-bundle.mjs.",
    "// Edit src/overlay/* instead, then run npm run build.",
    `export const vernierOverlayBundle = ${JSON.stringify(bundled)};`,
    "",
  ].join("\n"),
);
